sql:
SELECT 
  (SELECT COUNT(*) FROM charms) AS total_charms,
  (SELECT charm_name FROM charms ORDER BY version DESC LIMIT 1) AS charm_with_highest_version;

SELECT COUNT(*) as count
FROM charms
WHERE charm_id NOT IN (
  SELECT charm_id
  FROM documentation
);

SELECT COUNT(DISTINCT user_id) AS num_users
FROM user_access
WHERE charm_id = 1;

SELECT charm_name, version, updated_at 
FROM charms 
ORDER BY updated_at DESC;

SELECT AVG(total_bugs) AS avg_bugs_per_charm
FROM (
  SELECT charm_id, COUNT(bug_id) AS total_bugs
  FROM bugs
  GROUP BY charm_id
) AS subquery;

external_knowledge:
- 'trailblazers' refers to unique users who have accessed a charm; 
- 'stumbled upon' refers to users who have accessed a charm at least once; 
- 'specific gem' refers to the charm with the name 'specific_charm_name'.
